# Let me build a complete solution

def solve(grid):
    import numpy as np
    from collections import deque

    grid = np.array(grid)
    H, W = grid.shape

    # Find gray bbox
    gray_mask = grid == 5
    gray_pos = np.argwhere(gray_mask)
    gr_min, gc_min = int(gray_pos[:,0].min()), int(gray_pos[:,1].min())
    gr_max, gc_max = int(gray_pos[:,0].max()), int(gray_pos[:,1].max())
    out_h = gr_max - gr_min + 1
    out_w = gc_max - gc_min + 1

    # Clean grid
    grid_clean = grid.copy()
    grid_clean[gray_mask] = 0

    # Find shapes
    visited = np.zeros((H, W), bool)
    shapes = []
    for r in range(H):
        for c in range(W):
            if grid_clean[r, c] != 0 and not visited[r, c]:
                cells = []
                queue = deque([(r, c)])
                visited[r, c] = True
                while queue:
                    cr, cc = queue.popleft()
                    cells.append((cr, cc))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < H and 0 <= nc < W and not visited[nr, nc] and grid_clean[nr, nc] != 0:
                            visited[nr, nc] = True
                            queue.append((nr, nc))
                cells_arr = np.array(cells)
                shapes.append({
                    'rmin': int(cells_arr[:,0].min()),
                    'rmax': int(cells_arr[:,0].max()),
                    'cmin': int(cells_arr[:,1].min()),
                    'cmax': int(cells_arr[:,1].max()),
                })

    shapes.sort(key=lambda s: s['cmin'])
    n_shapes = len(shapes)

    for s in shapes:
        s['h'] = s['rmax'] - s['rmin'] + 1
        s['w'] = s['cmax'] - s['cmin'] + 1
        s['content'] = grid_clean[s['rmin']:s['rmax']+1, s['cmin']:s['cmax']+1]
        unique_colors = set(int(v) for v in s['content'].flatten() if v != 0)
        s['single_color'] = len(unique_colors) == 1
        s['color'] = int(list(unique_colors)[0]) if s['single_color'] else None

    single_color_mode = all(s['single_color'] for s in shapes)

    # Anchor type
    all_same_top = len(set(s['rmin'] for s in shapes)) == 1
    all_same_bot = len(set(s['rmax'] for s in shapes)) == 1

    if all_same_top:
        anchor_type = 'top'
        anchor_row = shapes[0]['rmin']
    elif all_same_bot:
        anchor_type = 'bottom'
        anchor_row = shapes[0]['rmax']
    else:
        anchor_type = 'center'
        rmin_s = max(s['rmin'] for s in shapes)
        rmax_s = min(s['rmax'] for s in shapes)
        anchor_row = (rmin_s + rmax_s) // 2

    # Column spacing and target index
    widths = [s['w'] for s in shapes]
    heights = [s['h'] for s in shapes]

    if n_shapes >= 2:
        col_spacing = shapes[1]['cmin'] - shapes[0]['cmin']
    else:
        col_spacing = widths[0] + 1

    target_idx = round((gc_min - shapes[0]['cmin']) / col_spacing)

    # Target dimensions
    if n_shapes >= 2:
        w_growth = (widths[-1] - widths[0]) / (n_shapes - 1)
        h_growth = (heights[-1] - heights[0]) / (n_shapes - 1)
    else:
        w_growth = 0
        h_growth = 0

    target_w = round(widths[0] + target_idx * w_growth)
    target_h = round(heights[0] + target_idx * h_growth)

    # Target color
    if single_color_mode:
        colors = [s['color'] for s in shapes]
        for cycle_len in range(1, n_shapes + 1):
            if all(colors[i] == colors[i % cycle_len] for i in range(n_shapes)):
                break
        target_color = colors[target_idx % cycle_len]

    # Target position
    target_cmin = gc_min
    if anchor_type == 'top':
        target_rmin = anchor_row
        target_rmax = target_rmin + target_h - 1
    elif anchor_type == 'bottom':
        target_rmax = anchor_row
        target_rmin = target_rmax - target_h + 1
    else:
        target_rmin = round(anchor_row - (target_h - 1) / 2)
        target_rmax = target_rmin + target_h - 1

    # Build binary value table (for single_color) or color value table
    shape_w = widths[0]  # Assume fixed width for value table columns
    if not all(w == shape_w for w in widths):
        shape_w = max(widths)  # Variable width; we'll handle c_shape mapping

    # For each (distance, c_shape), collect the value
    # For single color: store 1 (filled) or absent (empty)
    # For multi color: store the color value

    value_table = {}  # (d, c_shape) -> value

    for s in shapes:
        for c in range(s['w']):
            for r in range(s['h']):
                grid_r = s['rmin'] + r
                val = int(s['content'][r, c])
                if val == 0:
                    continue

                if anchor_type == 'top':
                    d = grid_r - anchor_row
                elif anchor_type == 'bottom':
                    d = anchor_row - grid_r
                else:
                    d = abs(grid_r - anchor_row)

                key = (d, c)
                if single_color_mode:
                    value_table[key] = 1  # binary
                else:
                    if key not in value_table:
                        value_table[key] = val

    # For each column c_shape, extract the sequence and detect period
    col_sequences = {}
    col_periods = {}

    for c in range(target_w):
        c_eff = min(c, shape_w - 1)  # Map wider columns to existing
        max_d_for_col = max((d for (d, cs) in value_table if cs == c_eff), default=-1)

        seq = []
        for d in range(max_d_for_col + 1):
            key = (d, c_eff)
            if key in value_table:
                seq.append(value_table[key])
            else:
                seq.append(0)

        col_sequences[c] = seq

        # Detect period
        if seq:
            p = len(seq)
            for pp in range(1, len(seq) + 1):
                if all(seq[i] == seq[i % pp] for i in range(len(seq))):
                    p = pp
                    break
            col_periods[c] = p
        else:
            col_periods[c] = 1

    # For multi-color shapes, try to improve period detection
    if not single_color_mode:
        max_period = max(col_periods.values())
        # Use max period for all columns if it's consistent
        for c in col_sequences:
            seq = col_sequences[c]
            if len(seq) < max_period:
                # Can't verify, assume max_period
                col_periods[c] = max_period
            else:
                col_periods[c] = max_period

    # Determine n (extent) for each column in the target shape
    # n[c_shape] = how far from anchor this column extends

    # For each c_shape, track n values across shapes
    col_n_values = {}  # c_shape -> list of n values

    for s_idx, s in enumerate(shapes):
        for c in range(s['w']):
            # Find the extent of this column
            col_data = s['content'][:, c]
            nonzero_rows = np.where(col_data != 0)[0]
            if len(nonzero_rows) == 0:
                continue

            if anchor_type == 'top':
                n_val = int(nonzero_rows.max())  # distance from top row of shape
            elif anchor_type == 'bottom':
                n_val = s['h'] - 1 - int(nonzero_rows.min())  # distance from bottom
            else:
                center_in_shape = (s['h'] - 1) // 2
                n_val = max(abs(int(nonzero_rows.max()) - center_in_shape),
                           abs(int(nonzero_rows.min()) - center_in_shape))

            if c not in col_n_values:
                col_n_values[c] = []
            col_n_values[c].append(n_val)

    # Extrapolate n for the target shape
    target_n = {}
    for c in range(target_w):
        c_eff = min(c, shape_w - 1)
        if c_eff in col_n_values:
            n_vals = col_n_values[c_eff]
            if len(n_vals) >= 2:
                # Detect pattern in n_vals
                diffs = [n_vals[i+1] - n_vals[i] for i in range(len(n_vals)-1)]
                # Check if diffs alternate between two values
                if len(set(diffs)) == 1:
                    next_diff = diffs[0]
                elif len(set(diffs)) == 2:
                    # Alternating pattern
                    next_diff = diffs[0] if len(diffs) % 2 == 0 else diffs[1]
                else:
                    next_diff = diffs[-1]

                steps_ahead = target_idx - (n_shapes - 1)
                # Need to extrapolate from last known n_val
                current_n = n_vals[-1]
                # Apply diffs for each step
                for step in range(steps_ahead):
                    step_idx = len(diffs) + step
                    if len(set(diffs)) == 2:
                        d_vals = sorted(set(diffs))
                        d = d_vals[0] if step_idx % 2 == (0 if diffs[0] == d_vals[0] else 1) else d_vals[1]
                    else:
                        d = diffs[-1] if diffs else 0
                    current_n += d
                target_n[c] = current_n
            else:
                target_n[c] = n_vals[0]
        else:
            target_n[c] = target_h - 1  # default: full height

    # Generate output
    output = np.zeros((out_h, out_w), dtype=int)

    for or_ in range(out_h):
        for oc in range(out_w):
            grid_r = gr_min + or_
            grid_c = gc_min + oc

            c_shape = oc
            c_eff = min(c_shape, shape_w - 1)

            # Compute distance from anchor
            if anchor_type == 'top':
                d = grid_r - anchor_row
            elif anchor_type == 'bottom':
                d = anchor_row - grid_r
            else:
                d = abs(grid_r - anchor_row)

            # Check if within column extent
            n_col = target_n.get(c_shape, target_h - 1)
            if d > n_col:
                output[or_, oc] = 0
                continue

            # Get value
            seq = col_sequences.get(c_shape, col_sequences.get(c_eff, []))
            p = col_periods.get(c_shape, col_periods.get(c_eff, 1))

            if d < len(seq):
                val = seq[d]
            else:
                # Extrapolate with period
                if p > 0 and len(seq) > 0:
                    val = seq[d % p]
                else:
                    val = 0

            if single_color_mode:
                output[or_, oc] = target_color if val else 0
            else:
                output[or_, oc] = val

    return output.tolist()

# Test on all training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        print(f"  Expected: {expected[:3]}...")
        print(f"  Got:      {result[:3]}...")
        # Find differences
        for r in range(min(len(result), len(expected))):
            for c in range(min(len(result[0]), len(expected[0]))):
                if result[r][c] != expected[r][c]:
                    print(f"  Diff at ({r},{c}): expected {expected[r][c]}, got {result[r][c]}")

