                n_val = s['h'] - 1 - int(nonzero_rows.min())
            else:
                center_in_shape = (s['h'] - 1) // 2
                n_val = max(abs(int(nonzero_rows.max()) - center_in_shape),
                           abs(int(nonzero_rows.min()) - center_in_shape))
            if c not in col_n_values:
                col_n_values[c] = []
            col_n_values[c].append(n_val)

    target_n = {}
