                diffs = [n_vals[i+1] - n_vals[i] for i in range(len(n_vals)-1)]
                unique_diffs = sorted(set(diffs))

                steps = target_idx - n_shapes + 1
                current_n = n_vals[-1]

                for step in range(steps):
                    d_idx = len(diffs) + step
                    if len(unique_diffs) == 1:
                        d = unique_diffs[0]
                    elif len(unique_diffs) == 2:
                        # Determine alternation phase
                        phase = 0 if diffs[0] == unique_diffs[0] else 1
                        d = unique_diffs[(d_idx + phase) % 2]
                    else:
                        d = diffs[-1]
                    current_n += d

                target_n[c] = current_n
            elif len(n_vals) == 1:
                # Single shape, use growth rule
                if anchor_type == 'center':
                    target_n[c] = (target_h - 1) // 2
                else:
                    target_n[c] = target_h - 1
            else:
                target_n[c] = target_h - 1
        else:
            target_n[c] = target_h - 1

    # Generate output
    output = np.zeros((out_h, out_w), dtype=int)

    for or_ in range(out_h):
        for oc in range(out_w):
            grid_r = gr_min + or_
            c_shape = oc
            c_eff = min(c_shape, ref_w - 1)

            if anchor_type == 'top':
                d = grid_r - anchor_row
            elif anchor_type == 'bottom':
                d = anchor_row - grid_r
            else:
                d = abs(grid_r - anchor_row)

            n_col = target_n.get(c_shape, target_n.get(c_eff, target_h - 1))
            if d > n_col or d < 0:
                continue

            seq = col_padded.get(c_shape, col_padded.get(c_eff, []))
            p = col_periods.get(c_shape, col_periods.get(c_eff, 1))

            if not seq or p <= 0:
                continue

            idx = d % p
            if idx < len(seq):
                val = seq[idx]
            else:
                val = 0

            if single_color_mode:
                output[or_, oc] = target_color if val else 0
            else:
                output[or_, oc] = val

    return output.tolist()

